import React, { useState, useEffect } from 'react';
import jwtDecode from 'jwt-decode';

const clientId = 'YOUR_CLIENT_ID';
const redirectUri = 'http://localhost:3000/callback';
const authorizationEndpoint = 'https://your-authorization-server.com/auth';
const tokenEndpoint = 'https://your-authorization-server.com/token';

function App() {
  const [user, setUser] = useState(null);

  useEffect(() => {
    const urlParams = new URLSearchParams(window.location.search);
    const code = urlParams.get('code');
    const state = urlParams.get('state');
    const storedState = sessionStorage.getItem('oidc_state');

    if (code && state === storedState) {
      sessionStorage.removeItem('oidc_state');
      exchangeCodeForTokens(code);
    }
  }, []);

  const login = () => {
    const state = generateRandomString();
    sessionStorage.setItem('oidc_state', state);
    const authUrl = `${authorizationEndpoint}?response_type=code&client_id=${clientId}&redirect_uri=${encodeURIComponent(redirectUri)}&state=${state}`;
    window.location.href = authUrl;
  };

  const exchangeCodeForTokens = async (code) => {
    try {
      const response = await fetch(tokenEndpoint, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: new URLSearchParams({
          grant_type: 'authorization_code',
          code,
          redirect_uri: redirectUri,
          client_id: clientId,
        }),
      });
      const data = await response.json();
      const idToken = data.id_token;
      const userProfile = jwtDecode(idToken);
      setUser(userProfile);
    } catch (error) {
      console.error('Error exchanging code for tokens', error);
    }
  };

  const generateRandomString = () => {
    const array = new Uint32Array(28);
    window.crypto.getRandomValues(array);
    return Array.from(array, dec => ('0' + dec.toString(16)).substr(-2)).join('');
  };

  return (
    <div>
      <h1>React OIDC Authentication</h1>
      {user ? (
        <div>
          <h2>Welcome, {user.name}</h2>
          <pre>{JSON.stringify(user, null, 2)}</pre>
        </div>
      ) : (
        <button onClick={login}>Login</button>
      )}
    </div>
  );
}

export default App;